import React from 'react';
import { Box, IconButton, ListItemIcon, ListItemText, Menu, MenuItem, TableCell, TableRow, Tooltip, Typography } from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import PhoneIcon from '@mui/icons-material/Phone';
import ContactPhoneIcon from '@mui/icons-material/ContactPhone';
import WhatsAppIcon from '@mui/icons-material/WhatsApp';
import InfoIcon from '@mui/icons-material/Info';
import RestaurantIcon from '@mui/icons-material/Restaurant';
import CurrencyRupeeIcon from '@mui/icons-material/CurrencyRupee';
import EditIcon from '@mui/icons-material/Edit';
import MoreVertIcon from '@mui/icons-material/MoreVert';
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';
import { AttendeeBasicInfo } from '@/types/attendee.types';
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { UnixDateTimeToReadable } from '@/utils/common';

// Helper – kept here to avoid being recreated on each parent render
const formatPhoneNumber = (phone: string): string => {
    if (!phone) return '';
    const cleaned = phone.replace(/\D/g, '');
    if (cleaned.length === 10) return `91${cleaned}`;
    if (cleaned.startsWith('91') && cleaned.length === 12) return cleaned;
    return cleaned;
};

export interface AttendeeRowProps {
    attendee: AttendeeBasicInfo;
    isCheckinEnabled: boolean;
    getFoodColor: (foodPref: string) => { bg: string; text: string };
    onInfo: (attendee: AttendeeBasicInfo) => void;
    onDonation: (attendee: AttendeeBasicInfo) => void;
    onCancel: (attendee: AttendeeBasicInfo) => void;
    onCheckIn: (attendee: AttendeeBasicInfo) => void;
    onUpdate: (attendee: AttendeeBasicInfo) => void;
}

const AttendeeRowImpl: React.FC<AttendeeRowProps> = ({
    attendee,
    isCheckinEnabled,
    getFoodColor,
    onInfo,
    onDonation,
    onCancel,
    onCheckIn,
    onUpdate,
}) => {
    const checkedIn = (attendee.checkedInAt ?? 0) > 0;
    const headCount = attendee.headCount ?? 1;
    const phone = attendee.profile?.phone ?? '';

    const [menuAnchor, setMenuAnchor] = React.useState<null | HTMLElement>(null);
    const closeMenu = () => setMenuAnchor(null);
    const runAction = (fn: () => void) => () => { closeMenu(); fn(); };

    const [profileDialogOpen, setProfileDialogOpen] = React.useState<boolean>(false);

    return (
        <TableRow
            hover
            sx={{
                backgroundColor: checkedIn ? 'rgba(76, 175, 80, 0.08)' : 'inherit',
                '&:hover': {
                    backgroundColor: checkedIn ? 'rgba(76, 175, 80, 0.15)' : undefined,
                },
            }}
        >
            <TableCell sx={{ py: { xs: 0.5, sm: 1.5 }, px: { xs: 0.5, sm: 1 } }}>
                {/* Line 1: Name */}
                <Box sx={{ mb: 0.2, display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <Box
                        component="span"
                        onClick={() => setProfileDialogOpen(true)}
                        sx={{
                            cursor: 'pointer',
                            color: 'primary.main',
                            fontWeight: 500,
                            fontSize: '0.9rem',
                            '&:hover': { textDecoration: 'underline' },
                        }}
                    >
                        {attendee.profile?.name}
                    </Box>
                </Box>

                <ProfileInfoDialog
                    open={profileDialogOpen}
                    profileId={attendee.userId}
                    mode="public"
                    onClose={() => setProfileDialogOpen(false)}
                />

                {/* Line 2: check-in icon | x1 | batch */}
                <Box sx={{ fontSize: '0.85rem', color: 'text.disabled', display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <Tooltip title={checkedIn ? `Checked in - ${UnixDateTimeToReadable(attendee.checkedInAt ?? 0)}` : 'Not checked in'}>
                        <CheckCircleIcon
                            sx={{
                                fontSize: '1.05rem',
                                color: checkedIn ? 'success.main' : 'text.disabled',
                            }}
                        />
                    </Tooltip>

                    {attendee.donation && attendee.donation.trim() !== '' && (
                        <Tooltip title={`Donated: ₹${calculateDonationTotal(attendee.donation)}`}>
                            <CurrencyRupeeIcon sx={{ fontSize: '1.05rem', color: 'success.main' }} />
                        </Tooltip>
                    )}

                    {attendee.foodPreference && attendee.foodPreference.trim() !== '' && (
                        <Tooltip title={`Food: ${attendee.foodPreference}`}>
                            <RestaurantIcon
                                sx={{
                                    fontSize: '1.05rem',
                                    color: getFoodColor(attendee.foodPreference).text,
                                }}
                            />
                        </Tooltip>
                    )}

                    <Typography
                        component="span"
                        variant="body2"
                        sx={{
                            px: 0.6,
                            py: 0.1,
                            backgroundColor: headCount > 1 ? 'primary.main' : 'grey.400',
                            color: 'white',
                            borderRadius: '4px',
                            fontSize: '0.75rem',
                            fontWeight: 600,
                        }}
                    >
                        x{headCount}
                    </Typography>

                    <Typography component="span" variant="body2" sx={{ color: 'text.secondary', fontSize: '0.85rem' }}>
                        ({attendee.profile?.batch})
                    </Typography>
                </Box>
            </TableCell>

            {/* Action buttons */}
            <TableCell align="right" sx={{ py: { xs: 0.5, sm: 1.5 }, pl: 0, pr: { xs: 0.25, sm: 1 } }}>
                <Box sx={{ display: 'flex', gap: 0.3, justifyContent: 'flex-end' }}>
                    <Tooltip title="Manage">
                        <IconButton
                            onClick={(e) => setMenuAnchor(e.currentTarget)}
                            sx={{ padding: { xs: '4px', sm: '8px' } }}
                            aria-label="manage attendee"
                            aria-haspopup="menu"
                            aria-expanded={Boolean(menuAnchor) || undefined}
                        >
                            <MoreVertIcon sx={{ fontSize: { xs: '20px', sm: '24px' } }} />
                        </IconButton>
                    </Tooltip>

                    <Menu
                        anchorEl={menuAnchor}
                        open={Boolean(menuAnchor)}
                        onClose={closeMenu}
                        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
                        transformOrigin={{ vertical: 'top', horizontal: 'right' }}
                        slotProps={{
                            paper: {
                                sx: {
                                    borderRadius: 2,
                                    minWidth: 220,
                                    // Allow the full action list to render on tall mobile viewports
                                    // without being capped to ~50vh by the default Popover behaviour.
                                    maxHeight: { xs: 'calc(100vh - 16px)', sm: '80vh' },
                                    overflowY: 'auto',
                                    // Dashed separator between every menu row
                                    '& .MuiList-root > *:not(:last-child)': {
                                        borderBottom: '1px dashed',
                                        borderColor: 'divider',
                                    },
                                },
                            },
                        }}
                    >
                        <Box sx={{ px: 2, py: 1 }}>
                            <Typography variant="caption" color="text.secondary" sx={{ display: 'block', lineHeight: 1.2 }}>
                                Managing
                            </Typography>
                            <Typography variant="subtitle2" sx={{ fontWeight: 700, lineHeight: 1.3 }}>
                                {attendee.profile?.name || 'Attendee'}
                                {attendee.profile?.batch ? (
                                    <Typography component="span" variant="caption" color="text.secondary" sx={{ ml: 0.75 }}>
                                        ({attendee.profile.batch})
                                    </Typography>
                                ) : null}
                            </Typography>
                        </Box>
                        <MenuItem onClick={runAction(() => onInfo(attendee))}>
                            <ListItemIcon>
                                <InfoIcon fontSize="small" color="info" />
                            </ListItemIcon>
                            <ListItemText
                                primary="View details"
                                secondary="Full attendee info, donations, history"
                            />
                        </MenuItem>
                        {phone && (
                            <MenuItem disableRipple sx={{ cursor: 'default', '&:hover': { backgroundColor: 'transparent' } }}>
                                <ListItemIcon>
                                    <ContactPhoneIcon fontSize="small" sx={{ color: 'action.active' }} />
                                </ListItemIcon>
                                <ListItemText
                                    primary="Contact"
                                    secondary="Call or WhatsApp"
                                />
                                <Tooltip title={`Call ${phone}`}>
                                    <IconButton
                                        size="small"
                                        component="a"
                                        href={`tel:${phone}`}
                                        onClick={closeMenu}
                                        sx={{ ml: 1 }}
                                    >
                                        <PhoneIcon fontSize="small" color="primary" />
                                    </IconButton>
                                </Tooltip>
                                <Tooltip title="WhatsApp">
                                    <IconButton
                                        size="small"
                                        component="a"
                                        href={`https://wa.me/${formatPhoneNumber(phone)}`}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        onClick={closeMenu}
                                        sx={{ ml: 1 }}
                                    >
                                        <WhatsAppIcon fontSize="small" sx={{ color: '#25D366' }} />
                                    </IconButton>
                                </Tooltip>
                            </MenuItem>
                        )}
                        {isCheckinEnabled && (
                            <MenuItem
                                onClick={runAction(() => onCheckIn(attendee))}
                                disabled={checkedIn}
                            >
                                <ListItemIcon>
                                    <CheckCircleIcon fontSize="small" color={checkedIn ? 'disabled' : 'success'} />
                                </ListItemIcon>
                                <ListItemText
                                    primary={checkedIn ? 'Already checked in' : 'Check in'}
                                    secondary={
                                        checkedIn
                                            ? `At ${UnixDateTimeToReadable(attendee.checkedInAt ?? 0)}`
                                            : 'Mark attendee as present'
                                    }
                                />
                            </MenuItem>
                        )}
                        <MenuItem onClick={runAction(() => onUpdate(attendee))}>
                            <ListItemIcon>
                                <EditIcon fontSize="small" color="primary" />
                            </ListItemIcon>
                            <ListItemText
                                primary="Edit registration"
                                secondary="Update headcount or food preference"
                            />
                        </MenuItem>
                        <MenuItem onClick={runAction(() => onDonation(attendee))}>
                            <ListItemIcon>
                                <CurrencyRupeeIcon fontSize="small" sx={{ color: 'secondary.main' }} />
                            </ListItemIcon>
                            <ListItemText
                                primary="Add donation"
                                secondary="Record a contribution"
                            />
                        </MenuItem>
                        <MenuItem
                            onClick={runAction(() => onCancel(attendee))}
                            disabled={(attendee.headCount ?? 0) === 0}
                            sx={{ color: 'error.main' }}
                        >
                            <ListItemIcon>
                                <CancelIcon fontSize="small" color="error" />
                            </ListItemIcon>
                            <ListItemText
                                primary="Cancel registration"
                                secondary={(attendee.headCount ?? 0) === 0 ? 'Headcount already zero' : 'Set headcount to zero'}
                            />
                        </MenuItem>
                    </Menu>
                </Box>
            </TableCell>
        </TableRow>
    );
};

// Custom equality: re-render the row only when *its* attendee object or relevant flags change.
// All callbacks are required to be stable (useCallback with no changing deps) by the parent.
export const AttendeeRow = React.memo(AttendeeRowImpl, (prev, next) => {
    return (
        prev.attendee === next.attendee &&
        prev.isCheckinEnabled === next.isCheckinEnabled &&
        prev.getFoodColor === next.getFoodColor &&
        prev.onInfo === next.onInfo &&
        prev.onDonation === next.onDonation &&
        prev.onCancel === next.onCancel &&
        prev.onCheckIn === next.onCheckIn &&
        prev.onUpdate === next.onUpdate
    );
});
